const data = $input.first().json;

// Sort by budget (highest to lowest)
data.Leads.sort((a, b) => b.Budget - a.Budget);

// Convert to text
const text = data.Leads
  .map((lead, index) => `
${index + 1}.
Name: ${lead["Full Name"]}
Email: ${lead.Email}
Service: ${lead.Services}
Budget: ${lead.Budget}
Date: ${lead.Date}
`)
  .join('\n');

return [
  {
    json: {
      text
    }
  }
];

